// ====================================
// Parse page & STORE in staticData
// + Include preview_child_comments (replies)
// ====================================

const raw = $input.first().json;

const staticData = $getWorkflowStaticData('global');
if (!staticData.allComments) staticData.allComments = [];
staticData.currentPage = (staticData.currentPage || 0) + 1;

// Error check
if (raw.message && raw.status === 'fail') {
  console.log(`❌ Error: ${raw.message}`);
  return [{ json: { shouldContinue: false } }];
}

if (typeof raw === 'string' && raw.includes('<!DOCTYPE')) {
  console.log('❌ Instagram returned HTML — session expired.');
  return [{ json: { shouldContinue: false } }];
}

// Helper: simplify a reply comment
function simplifyReply(r) {
  return {
    id: String(r.pk || r.id || ''),
    username: r.user?.username || 'unknown',
    fullName: r.user?.full_name || '',
    isVerified: r.user?.is_verified || false,
    isAuthor: r.is_created_by_media_owner || false,
    text: r.text || '',
    createdAt: r.created_at,
    createdAtISO: r.created_at ? new Date(r.created_at * 1000).toISOString() : null,
    likeCount: r.comment_like_count || 0,
  };
}

// Parse comments from this page
const pageComments = (raw.comments || []).map(c => {
  // Simplify preview_child_comments (replies)
  const replies = (c.preview_child_comments || []).map(simplifyReply);

  return {
    id: String(c.pk || c.id || ''),
    username: c.user?.username || 'unknown',
    fullName: c.user?.full_name || '',
    isVerified: c.user?.is_verified || false,
    isPrivate: c.user?.is_private || false,
    text: c.text || '',
    createdAt: c.created_at,
    createdAtISO: c.created_at ? new Date(c.created_at * 1000).toISOString() : null,
    likeCount: c.comment_like_count || 0,
    childCommentCount: c.child_comment_count || 0,
    // ✅ Include simplified replies
    preview_child_comments: replies,
  };
});

staticData.allComments.push(...pageComments);
staticData.commentCount = raw.comment_count || staticData.allComments.length;

const hasMore = raw.has_more_comments || raw.has_more_headload_comments || false;
const nextMinId = raw.next_min_id || '';
const shouldContinue = hasMore && nextMinId && staticData.currentPage < 50 && pageComments.length > 0;

console.log(`📄 Page ${staticData.currentPage}: +${pageComments.length} comments (total: ${staticData.allComments.length}/${staticData.commentCount})`);

let config;
try {
  config = $('Config + Media ID1').first().json;
} catch(e) {
  config = $('Loop Back').first().json;
}

return [{ json: {
  shortcode: config.shortcode,
  mediaId: config.mediaId,
  postUrl: config.postUrl,
  cookie: config.cookie,
  csrftoken: config.csrftoken,
  nextMinId,
  shouldContinue,
}}];

const input = $input.first().json;
console.log(`🔄 Looping... (nextMinId: ${input.nextMinId})`);
return [{ json: input }];

// ====================================
// Output: 1 row per comment + replies
// ====================================

const data = $input.first().json;
const comments = data.comments || [];

if (comments.length === 0) {
  return [{ json: {
    status: 'empty',
    message: `Tidak ada komentar dari ${data.postUrl}`,
  }}];
}

console.log(`📊 Exporting ${comments.length} comments as rows`);

return comments.map((c, i) => ({
  json: {
    no: i + 1,


    username: c.username,
    full_name: c.fullName,
    is_verified: c.isVerified,
    comment_text: c.text,
    likes: c.likeCount,
    is_private: c.isPrivate,
    replies: c.preview_child_comments,
    posted_at: c.createdAtISO,

  }
}));

// ====================================
// CONFIG + SHORTCODE TO MEDIA ID
// ====================================


// const POST_URL = 'https://www.instagram.com/p/DOq9TFQE1z2/';
const POST_URL = 'https://www.instagram.com/p/DOOAI7dksMY/';

const SESSIONID = 'randomid';
const CSRFTOKEN = 'random';
const DS_USER_ID = '37138889879';

const MAX_PAGES = 1000;

const match = POST_URL.match(/\/(?:p|reel|tv)\/([A-Za-z0-9_-]+)/);
if (!match) throw new Error('Invalid Instagram URL');
const shortcode = match[1];

function shortcodeToMediaId(shortcode) {
  const alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_';
  let mediaId = BigInt(0);
  for (const char of shortcode) {
    mediaId = mediaId * BigInt(64) + BigInt(alphabet.indexOf(char));
  }
  return mediaId.toString();
}

const mediaId = shortcodeToMediaId(shortcode);
const cookie = `sessionid=${SESSIONID}; csrftoken=${CSRFTOKEN}; ds_user_id=${DS_USER_ID}; ig_nrcb=1;`;

const staticData = $getWorkflowStaticData('global');
staticData.allComments = [];
staticData.currentPage = 0;
staticData.commentCount = 0;

console.log(`Shortcode: ${shortcode} → Media ID: ${mediaId}`);

return [{ json: {
  shortcode,
  mediaId,
  postUrl: POST_URL,
  cookie,
  csrftoken: CSRFTOKEN,
  maxPages: MAX_PAGES,
  nextMinId: '',
  hasMore: true,
}}];

// ====================================
// ✅ FINAL: Ambil SEMUA comments dari staticData
// ====================================

const staticData = $getWorkflowStaticData('global');
const allComments = staticData.allComments || [];
const commentCount = staticData.commentCount || 0;
const pagesScraped = staticData.currentPage || 0;

const input = $input.first().json;

console.log(`✅ FINAL: ${allComments.length} total comments from ${pagesScraped} pages`);

staticData.allComments = [];
staticData.currentPage = 0;
staticData.commentCount = 0;

if (allComments.length === 0) {
  return [{ json: {
    status: 'empty',
    message: 'Tidak ada komentar yang berhasil di-scrape.',
    pagesScraped,
  }}];
}

return [{ json: {
  postUrl: input.postUrl || '',
  shortcode: input.shortcode || '',
  mediaId: input.mediaId || '',
  totalCommentCount: commentCount,
  totalCollected: allComments.length,
  pagesScraped,
  scrapedAt: new Date().toISOString(),
  comments: allComments,
}}];

// Gabung semua items jadi 1 item
const allComments = $input.all().map(item => item.json);

return [{ json: {
  total: allComments.length,
  comments: allComments,
} }];
